"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[310],{3533(t,e,a){a.r(e),a.d(e,{comp:()=>d,data:()=>l});var r=a(641);const i={},d=(0,a(6262).A)(i,[["render",function(t,e){return(0,r.uX)(),(0,r.CE)("div",null,[...e[0]||(e[0]=[(0,r.Fv)('<h1 id="fraud-detection" tabindex="-1"><a class="header-anchor" href="#fraud-detection"><span>Fraud Detection</span></a></h1><p><strong>Auctions → Fraud Detection</strong> — <code>?page=wkafw-fraud</code></p><p>Rule-based, signal-driven fraud detection. Configure velocity / IP / behavior rules, see flagged users in real-time, auto-block on rule match.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-fraud-events.png" alt="Fraud Detection → Recent Events — live signal stream with rule, severity, user and timestamp"></p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-fraud-flags.png" alt="Fraud Detection → Active Flags — currently throttled / blocked users with the rule that fired and a clear-flag action"></p><h2 id="what-it-detects" tabindex="-1"><a class="header-anchor" href="#what-it-detects"><span>What it detects</span></a></h2><table><thead><tr><th>Pattern</th><th>Default rule</th></tr></thead><tbody><tr><td>Bid spam / botting</td><td><code>wkafw_bid_rate_limit</code> — max bids per minute per user (default 10)</td></tr><tr><td>Shilling (seller bidding own auction)</td><td>Auto-detected when the bidder is the auction&#39;s seller</td></tr><tr><td>Coordinated bidding</td><td>Multiple users from same IP / IP range bidding same auction</td></tr><tr><td>Account farming</td><td>New account &lt; 24 hrs old placing high-value bids</td></tr><tr><td>Chargeback abuse</td><td>User has &gt; 1 chargeback on prior orders</td></tr><tr><td>Fake winning</td><td>User wins → never pays → repeats</td></tr><tr><td>Email-only signup</td><td>No verified email + bid attempts</td></tr><tr><td>SSL bypass</td><td>Bid attempts over HTTP when <code>wkafw_require_ssl=yes</code></td></tr></tbody></table><h2 id="page-layout" tabindex="-1"><a class="header-anchor" href="#page-layout"><span>Page layout</span></a></h2><p>Four tabs:</p><ol><li><strong>Live signals</strong> — real-time view of bidders matching active rules</li><li><strong>Rules</strong> — configure thresholds</li><li><strong>Flagged users</strong> — review queue (manual decision required)</li><li><strong>Settings</strong> — global toggles</li></ol><h2 id="live-signals" tabindex="-1"><a class="header-anchor" href="#live-signals"><span>Live signals</span></a></h2><p>Streaming view (auto-refreshes every 10 seconds) showing the last 100 events that matched any rule.</p><table><thead><tr><th>Column</th><th>Source</th></tr></thead><tbody><tr><td>Time</td><td>event timestamp</td></tr><tr><td>Rule</td><td>which rule triggered</td></tr><tr><td>User</td><td>bidder user link</td></tr><tr><td>Auction</td><td>auction ID link</td></tr><tr><td>IP</td><td>source IP</td></tr><tr><td>Severity</td><td>low / medium / high (from rule config)</td></tr><tr><td>Action taken</td><td>logged / flagged / auto-blocked</td></tr></tbody></table><p>Click a row for the full request fingerprint.</p><h2 id="rules" tabindex="-1"><a class="header-anchor" href="#rules"><span>Rules</span></a></h2><p>Edit thresholds for each detection rule.</p><h3 id="bid-rate-limit" tabindex="-1"><a class="header-anchor" href="#bid-rate-limit"><span>Bid rate limit</span></a></h3><table><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>wkafw_bid_rate_limit</code></td><td>10 / min</td><td>Max bids per minute per user</td></tr><tr><td>Severity</td><td>medium</td><td>Logs + flags after threshold</td></tr><tr><td>Auto-block</td><td>off</td><td>Add user to <a href="/admin-users.html" target="_blank" rel="noopener noreferrer">Blocked Users</a> on threshold</td></tr></tbody></table><h3 id="ip-velocity" tabindex="-1"><a class="header-anchor" href="#ip-velocity"><span>IP velocity</span></a></h3><p>Multiple distinct users from the same IP placing bids:</p><table><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td>Distinct users / hour</td><td>5</td><td>Triggers if exceeded</td></tr><tr><td>IP block list</td><td>(empty)</td><td>Hard-block IPs at the bid form</td></tr><tr><td>IP allow list</td><td>(empty)</td><td>Bypass all rules for these IPs</td></tr></tbody></table><h3 id="account-age" tabindex="-1"><a class="header-anchor" href="#account-age"><span>Account age</span></a></h3><table><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td>Min account age</td><td>0 hrs</td><td>Block bids from accounts younger than this</td></tr><tr><td>Min account age for high-value</td><td>24 hrs</td><td>Above bid amount X, require older account</td></tr><tr><td>High-value threshold</td><td>1000</td><td>Currency amount</td></tr></tbody></table><h3 id="chargeback-memory" tabindex="-1"><a class="header-anchor" href="#chargeback-memory"><span>Chargeback memory</span></a></h3><table><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td>Block after N chargebacks</td><td>1</td><td>Auto-block on this many lifetime chargebacks</td></tr><tr><td>Memory window</td><td>365 days</td><td>How far back to count</td></tr></tbody></table><h3 id="email-verification" tabindex="-1"><a class="header-anchor" href="#email-verification"><span>Email verification</span></a></h3><table><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>wkafw_require_email_verify</code></td><td>no</td><td>Require verified email before bidding</td></tr></tbody></table><h3 id="ssl-gate" tabindex="-1"><a class="header-anchor" href="#ssl-gate"><span>SSL gate</span></a></h3><table><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>wkafw_require_ssl</code></td><td>no</td><td>Reject bids over HTTP (admins see notice on insecure setup)</td></tr></tbody></table><h2 id="flagged-users" tabindex="-1"><a class="header-anchor" href="#flagged-users"><span>Flagged users</span></a></h2><p>Manual review queue — users matched by rules but not auto-blocked.</p><table><thead><tr><th>Column</th><th>Source</th></tr></thead><tbody><tr><td>User</td><td>name + email</td></tr><tr><td>Triggered rules</td><td>rule names</td></tr><tr><td>First flag</td><td>timestamp</td></tr><tr><td>Last flag</td><td>timestamp</td></tr><tr><td>Match count</td><td>total events</td></tr><tr><td>Bids placed</td><td>lifetime</td></tr><tr><td>Decision</td><td>pending / cleared / blocked</td></tr></tbody></table><p>For each flagged user, admin chooses:</p><table><thead><tr><th>Decision</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Clear</strong></td><td>Remove flags; user resumes normal activity</td></tr><tr><td><strong>Block</strong></td><td>Add to <a href="/admin-users.html" target="_blank" rel="noopener noreferrer">Blocked Users</a></td></tr><tr><td><strong>Block IP</strong></td><td>Add the user&#39;s IP to the IP block list</td></tr><tr><td><strong>Investigate</strong></td><td>Park for follow-up; doesn&#39;t change state</td></tr></tbody></table><h2 id="bid-time-enforcement" tabindex="-1"><a class="header-anchor" href="#bid-time-enforcement"><span>Bid-time enforcement</span></a></h2><p>When a user clicks <strong>Place Bid</strong>, every active rule runs before the bid is accepted. Failure modes:</p><table><thead><tr><th>Result</th><th>What the bidder sees</th></tr></thead><tbody><tr><td>Pass all rules</td><td>Bid placed</td></tr><tr><td>Soft-fail (logged, allowed)</td><td>Bid placed; admin sees the flag</td></tr><tr><td>Hard-fail (rule violation)</td><td>&quot;Cannot place bid&quot; with reason (sanitized — never reveals rule logic)</td></tr><tr><td>User blocked</td><td>&quot;Account suspended — contact support&quot;</td></tr></tbody></table><h2 id="captcha-fallback" tabindex="-1"><a class="header-anchor" href="#captcha-fallback"><span>CAPTCHA fallback</span></a></h2><p>When a user is on the verge of triggering a rule (e.g. 8 of 10 bids per minute), the bid form auto-injects a <a href="/captcha.html" target="_blank" rel="noopener noreferrer">CAPTCHA challenge</a> — Cloudflare Turnstile, reCAPTCHA, or hCaptcha. Configure the provider and threshold under <strong>Settings → Trust &amp; Security</strong>.</p><h2 id="reporting" tabindex="-1"><a class="header-anchor" href="#reporting"><span>Reporting</span></a></h2><p><a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports → Fraud</a> shows:</p><ul><li>Daily flag counts by rule</li><li>Top flagged users</li><li>IP heatmap</li><li>Auto-block / manual-block split</li><li>False-positive rate (cleared / total flags)</li></ul><h2 id="privacy-legal" tabindex="-1"><a class="header-anchor" href="#privacy-legal"><span>Privacy &amp; legal</span></a></h2><ul><li>Fraud signals contain user-identifying data — encrypted at rest if your database supports it</li><li>Retention: configurable, default 365 days; auto-purged thereafter</li><li>GDPR exporter includes fraud-flag records</li><li>Auto-block decisions are logged in <a href="/admin-audit-log.html" target="_blank" rel="noopener noreferrer">Audit Log</a> for due-process review</li></ul><h2 id="common-workflows" tabindex="-1"><a class="header-anchor" href="#common-workflows"><span>Common workflows</span></a></h2><h3 id="investigate-a-bid-spike" tabindex="-1"><a class="header-anchor" href="#investigate-a-bid-spike"><span>&quot;Investigate a bid spike&quot;</span></a></h3><ol><li><strong>Live signals</strong> tab → filter by <em>bid rate</em></li><li>Group by user → identify the spike source</li><li>Drill into bids (<a href="/admin-bids.html" target="_blank" rel="noopener noreferrer">Bids</a>) for IP / UA correlation</li><li>Block users + IP if confirmed bot</li></ol><h3 id="reduce-false-positives" tabindex="-1"><a class="header-anchor" href="#reduce-false-positives"><span>&quot;Reduce false positives&quot;</span></a></h3><ol><li><strong>Flagged users</strong> tab → filter by <em>cleared</em> decisions</li><li>Group by rule → identify which rules over-trigger</li><li><strong>Rules</strong> tab → relax that rule&#39;s threshold</li></ol><h3 id="onboard-a-new-auction-category-with-stricter-rules" tabindex="-1"><a class="header-anchor" href="#onboard-a-new-auction-category-with-stricter-rules"><span>&quot;Onboard a new auction category with stricter rules&quot;</span></a></h3><ol><li><strong>Rules</strong> tab → duplicate a rule</li><li>Scope: only certain WC categories</li><li>Save → live for auctions in those categories</li></ol>',51)])])}]]),l=JSON.parse('{"path":"/admin-fraud.html","title":"Fraud Detection","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"What it detects","slug":"what-it-detects","link":"#what-it-detects","children":[]},{"level":2,"title":"Page layout","slug":"page-layout","link":"#page-layout","children":[]},{"level":2,"title":"Live signals","slug":"live-signals","link":"#live-signals","children":[]},{"level":2,"title":"Rules","slug":"rules","link":"#rules","children":[{"level":3,"title":"Bid rate limit","slug":"bid-rate-limit","link":"#bid-rate-limit","children":[]},{"level":3,"title":"IP velocity","slug":"ip-velocity","link":"#ip-velocity","children":[]},{"level":3,"title":"Account age","slug":"account-age","link":"#account-age","children":[]},{"level":3,"title":"Chargeback memory","slug":"chargeback-memory","link":"#chargeback-memory","children":[]},{"level":3,"title":"Email verification","slug":"email-verification","link":"#email-verification","children":[]},{"level":3,"title":"SSL gate","slug":"ssl-gate","link":"#ssl-gate","children":[]}]},{"level":2,"title":"Flagged users","slug":"flagged-users","link":"#flagged-users","children":[]},{"level":2,"title":"Bid-time enforcement","slug":"bid-time-enforcement","link":"#bid-time-enforcement","children":[]},{"level":2,"title":"CAPTCHA fallback","slug":"captcha-fallback","link":"#captcha-fallback","children":[]},{"level":2,"title":"Reporting","slug":"reporting","link":"#reporting","children":[]},{"level":2,"title":"Privacy & legal","slug":"privacy-legal","link":"#privacy-legal","children":[]},{"level":2,"title":"Common workflows","slug":"common-workflows","link":"#common-workflows","children":[{"level":3,"title":"\\"Investigate a bid spike\\"","slug":"investigate-a-bid-spike","link":"#investigate-a-bid-spike","children":[]},{"level":3,"title":"\\"Reduce false positives\\"","slug":"reduce-false-positives","link":"#reduce-false-positives","children":[]},{"level":3,"title":"\\"Onboard a new auction category with stricter rules\\"","slug":"onboard-a-new-auction-category-with-stricter-rules","link":"#onboard-a-new-auction-category-with-stricter-rules","children":[]}]}],"git":{},"filePathRelative":"admin-fraud.md"}')}}]);